head.b:skin:
/* === MODER DARK THEME (Inspired by Image 1) === */
:root {
    --bg-dark: #121212;
    --card-bg: #1e1e1e;
    --text-main: #e0e0e0;
    --text-dim: #a0a0a0;
    --accent: #ce0000;
}

body {
    margin: 0; padding: 0;
    font-family: 'Vazir', sans-serif;
    background-color: var(--bg-dark);
    color: var(--text-main);
    line-height: 1.8;
}

a { text-decoration: none; color: inherit; transition: 0.3s; }
img { max-width: 100%; height: auto; border: 0; }
* { box-sizing: border-box; outline: none; }

/* HEADER */
.site-header { background: #000; padding: 25px 0; border-bottom: 3px solid var(--accent); position:sticky; top:0; z-index:100; }
.header-content { max-width: 1200px; margin: 0 auto; padding: 0 15px; display: flex; justify-content: space-between; align-items: center; }
.logo-main { font-size: 30px; font-weight: 900; color: white; text-transform: uppercase; letter-spacing: 1px; }
.logo-main span { color: var(--accent); }

/* MAIN CONTAINER (2 columns) */
.main-wrapper {
    max-width: 1200px; margin: 40px auto; padding: 0 15px;
    display: grid; grid-template-columns: 1fr 300px; gap: 40px;
}

/* === BLOG POSTS LIST === */
.blog-posts { display: flex; flex-direction: column; gap: 50px; }

/* Individual Post Card */
.post-outer { border-bottom: 1px solid #333; padding-bottom: 50px; }
.post-outer:last-child { border: none; }

/* TITLES */
h3.post-title { font-size: 28px !important; font-weight: 900 !important; margin: 0 0 20px 0 !important; line-height: 1.4 !important; }
h3.post-title a { color: #fff !important; }
h3.post-title a:hover { color: var(--accent) !important; }

/* POST BODY (Content Area) */
.post-body { font-size: 16px; color: var(--text-main); }

/* FORCE IMAGES TO SHOW */
.post-body img {
    display: block !important;
    width: 100% !important;
    max-width: 900px !important;
    height: auto !important;
    margin: 25px auto !important;
    border-radius: 12px;
    box-shadow: 0 10px 40px rgba(0,0,0,0.5);
    border: 1px solid #333;
}

/* Hide Meta and Other Stuff we don't need */
/* READ MORE BUTTON */
.jump-link { display: block !important; margin-top: 25px; text-align: left; }
.jump-link a { 
    background: var(--accent); 
    color: #fff !important; 
    padding: 10px 25px; 
    border-radius: 6px; 
    font-weight: 900; 
    font-size: 14px; 
    box-shadow: 0 4px 15px rgba(206,0,0,0.4);
    display: inline-block;
}
.jump-link a:hover { background: #fff !important; color: var(--accent) !important; box-shadow: 0 6px 20px rgba(0,0,0,0.5); }

/* SIDEBAR */
.sidebar-box { background: var(--card-bg); border-radius: 12px; padding: 25px; margin-bottom: 30px; border: 1px solid #333; }
.widget-title { font-size: 16px; font-weight: 900; color: #fff; margin-bottom: 20px; border-right: 4px solid var(--accent); padding-right: 15px; }

/* FOOTER */
.site-footer { padding: 40px 0; border-top: 1px solid #333; text-align: center; color: var(--text-dim); }

/* RTL Fix for Blogger */
body { direction: rtl; }

@media (max-width: 900px) {
    .main-wrapper { grid-template-columns: 1fr; }
    h3.post-title { font-size: 22px !important; }
}

div.script:
                document.addEventListener("DOMContentLoaded", function () {
                    const ctx = document.getElementById('hrChart').getContext('2d');
                    new Chart(ctx, {
                        type: 'doughnut',
                        data: {
                            labels: ['اعدام', 'زندانی', 'نقض'],
                            datasets: [{ data: [120, 240, 1150], backgroundColor: ['#ce0000', '#f57f17', '#333'], borderWidth: 0 }]
                        },
                        options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, cutout: '70%' }
                    });
                    document.getElementById('stats-legend').innerHTML = `

■ اعدام‌های ثبت شده120

■ بازداشت سیاسی240
                    `;
                });
